chapterContent.content:
//html||@js:
var s = String(result || '').trim();
if(!s) return '';
var obj = null;
try {
  obj = JSON.parse(s);
} catch (e) {
  var ms = s.match(/\{[\s\S]*\}/);
  if(ms){
    try { obj = JSON.parse(ms[0]); } catch (e2) {}
  }
}
var t = '';
if(obj && obj.status == 1 && obj.data && obj.data.content){
  t = String(obj.data.content || '');
}else{
  var mc = s.match(/\"content\"\s*:\s*\"([\s\S]*?)\"\s*,\s*\"encoding\"/i);
  if(!mc) mc = s.match(/\"content\"\s*:\s*\"([\s\S]*?)\"\s*\}/i);
  if(!mc) return '';
  t = String(mc[1] || '');
  t = t.replace(/\\\//g, '/').replace(/\\n/g, '\n').replace(/\\r/g, '\n').replace(/\\t/g, ' ').replace(/\\\"/g, '"').replace(/\\\\/g, '\\');
}
t = t.replace(/<script[\s\S]*?<\/script>/ig, '');
t = t.replace(/<style[\s\S]*?<\/style>/ig, '');
t = t.replace(/<br\s*\/?\s*>/ig, '\n');
t = t.replace(/<\/p>/ig, '\n');
t = t.replace(/<\/div>/ig, '\n');
t = t.replace(/<[^>]+>/g, '');
t = t.replace(/&nbsp;|&#160;|\u00a0/g, ' ');
t = t.replace(/\r/g, '\n');
t = t.replace(/[ \t]+/g, ' ');
t = t.replace(/\n{3,}/g, '\n\n');
t = t.replace(/^.*阅读模式.*$/gmi, '');
t = t.replace(/^.*完整章.*请退出.*$/gmi, '');
return t.replace(/^\s+|\s+$/g, '');

chapterContent.requestInfo:
@js:
var u = '';
if(params && params.lastResponse && params.lastResponse.nextPageUrl){
  u = params.lastResponse.nextPageUrl;
}
if(!u && params && params.queryInfo){
  u = params.queryInfo.url || params.queryInfo.detailUrl || '';
}
if(!u && result){
  if(typeof result === 'string') u = result;
  else if(result.url) u = result.url;
  else if(result.detailUrl) u = result.detailUrl;
}
if(!u && params && params.responseUrl){
  u = params.responseUrl;
}
u = String(u || '').split('\\/').join('/').trim();
if(!u) return {'url':'','httpHeaders':config.httpHeaders};
if(!/^https?:\/\//i.test(u)){
  if(u.charAt(0) !== '/') u = '/' + u;
  u = config.host + u.replace(/^\/+/,'');
}
if(params && params.lastResponse && params.lastResponse.nextPageUrl){
  var headers = {};
  var baseHeaders = config.httpHeaders || {};
  for(var k in baseHeaders){
    if(baseHeaders.hasOwnProperty(k)) headers[k] = baseHeaders[k];
  }
  headers['X-Requested-With'] = 'XMLHttpRequest';
  var ref = '';
  if(params && params.queryInfo){
    ref = params.queryInfo.url || params.queryInfo.detailUrl || '';
  }
  ref = String(ref || '').split('\\/').join('/').trim();
  if(ref){
    if(!/^https?:\/\//i.test(ref)){
      if(ref.charAt(0) !== '/') ref = '/' + ref;
      ref = config.host + ref.replace(/^\/+/, '');
    }
    headers['Referer'] = ref;
  }else{
    headers['Referer'] = u;
  }
  return {'url':u,'httpHeaders':headers};
}
var m = u.match(/\/books\/(\d+)\/(\d+)\.html/i);
if(!m){
  return {'url':u,'httpHeaders':config.httpHeaders};
}
var jsUrl = config.host + 'scripts/chapter.js.php?aid=' + m[1] + '&cid=' + m[2] + '&referrer=' + encodeURIComponent(u.split('#')[0]);
return {'url':jsUrl,'httpHeaders':config.httpHeaders};

chapterContent.title:
@js:
if(params && params.queryInfo && params.queryInfo.title) return params.queryInfo.title;
return '';

chapterContent.nextPageUrl:
//html||@js:
var s = String(result || '');
if(!s || s.indexOf('chapterToken') < 0) return '';
var m1 = s.match(/chapterToken\s*=\s*['\"]([^'\"]+)['\"]/i);
var m2 = s.match(/timestamp\s*=\s*['\"]?([0-9]+)['\"]?/i);
var m3 = s.match(/nonce\s*=\s*['\"]([^'\"]+)['\"]/i);
if(!m1 || !m2 || !m3) return '';
var u = '';
if(params && params.queryInfo){
  u = params.queryInfo.url || params.queryInfo.detailUrl || '';
}
u = String(u || '').split('\\/').join('/').trim();
var m = u.match(/\/books\/(\d+)\/(\d+)\.html/i);
if(!m) return '';
return config.host + 'modules/article/ajax2.php?aid=' + m[1] + '&cid=' + m[2] + '&token=' + encodeURIComponent(m1[1]) + '&timestamp=' + encodeURIComponent(m2[1]) + '&nonce=' + encodeURIComponent(m3[1]);

